const t=JSON.parse('{"key":"v-7e212285","path":"/posts/%E6%B5%8B%E7%BB%98/%E6%91%84%E5%BD%B1%E6%B5%8B%E9%87%8F.html","title":"摄影测量","lang":"en-US","frontmatter":{"description":"摄影测量 摄影测量技术文档 1. 概述 摄影测量（Photogrammetry）是通过摄影手段获取目标物体的几何信息和物理信息，并进行分析和处理的一门学科和技术。它利用摄影机或其他传感器从不同角度获取目标物体的影像，通过影像处理和几何计算，重建目标物体的三维模型，并提取其几何、纹理、位置等信息。 2. 基本原理 摄影测量的基本原理是共线方程，即目标物体表面点、摄影机镜头中心和像点三点共线。通过至少两张从不同角度拍摄的影像，利用共线方程可以解算出目标物体表面点的三维坐标。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E6%91%84%E5%BD%B1%E6%B5%8B%E9%87%8F.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"摄影测量"}],["meta",{"property":"og:description","content":"摄影测量 摄影测量技术文档 1. 概述 摄影测量（Photogrammetry）是通过摄影手段获取目标物体的几何信息和物理信息，并进行分析和处理的一门学科和技术。它利用摄影机或其他传感器从不同角度获取目标物体的影像，通过影像处理和几何计算，重建目标物体的三维模型，并提取其几何、纹理、位置等信息。 2. 基本原理 摄影测量的基本原理是共线方程，即目标物体表面点、摄影机镜头中心和像点三点共线。通过至少两张从不同角度拍摄的影像，利用共线方程可以解算出目标物体表面点的三维坐标。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"摄影测量\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"摄影测量技术文档","slug":"摄影测量技术文档","link":"#摄影测量技术文档","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":3.47,"words":1040},"filePathRelative":"posts/测绘/摄影测量.md","localizedDate":"August 16, 2025","excerpt":"<h1> 摄影测量</h1>\\n<h2> 摄影测量技术文档</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>摄影测量（Photogrammetry）是通过摄影手段获取目标物体的几何信息和物理信息，并进行分析和处理的一门学科和技术。它利用摄影机或其他传感器从不同角度获取目标物体的影像，通过影像处理和几何计算，重建目标物体的三维模型，并提取其几何、纹理、位置等信息。</p>\\n<p><strong>2. 基本原理</strong></p>\\n<p>摄影测量的基本原理是<strong>共线方程</strong>，即目标物体表面点、摄影机镜头中心和像点三点共线。通过至少两张从不同角度拍摄的影像，利用共线方程可以解算出目标物体表面点的三维坐标。</p>","autoDesc":true}');export{t as data};
